+/// Probe profile with cost and covered features.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct ProbeProfile {
+    pub probe: ProbeType,
+    pub cost: f64,
+    pub features: Vec<FeatureKey>,
+}
+
+impl ProbeProfile {
+    pub fn new(probe: ProbeType, cost: f64, features: Vec<FeatureKey>) -> Self {
+        Self {
+            probe,
+            cost: cost.max(0.0),
+            features,
+        }
+    }
+}
